const HALLOKIN_IDLE_DATA = "data:image/png;base64,";

const HALLOKIN_RUN_DATA = "data:image/png;base64,";

// Coordinate system: positions and speeds are in WORLD pixels — same units as
// the unscaled tilemap canvas (16 px = 1 tile). Renderers scale up at draw.
const TILE_PX = 16;
const TILES_W = 36;
const TILES_H = 26;
const MAP_W = TILES_W * TILE_PX;     // 576 world-px
const MAP_H = TILES_H * TILE_PX;     // 416 world-px
const RENDER_SCALE = 4;              // 1 world-px = 4 screen-px in flat/tilt

const PLAYER_RADIUS = TILE_PX * 0.45;     // 7.2 world-px collision radius
const MOVE_SPEED = 9 * TILE_PX;            // 144 world-px/sec

// Sprite sheet metrics (per frame).
const FRAME_W = 192;
const FRAME_H = 128;
const IDLE_FRAMES = 6;
const IDLE_FPS = 8;
const RUN_FRAMES = 4;
const RUN_FPS = 12;
// Visible body inside the (mostly transparent) frame, in world-px.
// Tuned so the knight is ~2 tiles tall on the map. Keeps frame margin around it.
const SPRITE_DRAW_W = 36;   // world-px wide on map
const SPRITE_DRAW_H = 24;   // world-px tall on map

// Spawn on grass, north-center, well clear of fences and water.
const SPAWN_TILE = { col: 14, row: 4 };

// Solid tile ids. Water (80) and fence segments (28-33) block movement.
// EXCEPT: tile 79 (dock plank) on layer2 overrides water at the same cell.
const SOLID_IDS = new Set([80, 28, 29, 30, 31, 32, 33]);
const DOCK_ID   = 79;

// Compute per-cell solidity once. layers checked in order; cell is solid if
// any layer places a solid tile at that cell, UNLESS layer2 places a dock
// plank there (overrides water below).
function buildSolidGrid() {
  const m = CROSSING_TILEMAP;
  const layers = [m.layer1, m.layer2, m.layer3, m.layer4, m.layer5, m.layer6];
  const grid = new Uint8Array(m.width * m.height);
  for (let row = 0; row < m.height; row++) {
    for (let col = 0; col < m.width; col++) {
      const i = row * m.width + col;
      const dock = m.layer2[i] === DOCK_ID;
      let solid = 0;
      if (!dock) {
        for (const layer of layers) {
          if (SOLID_IDS.has(layer[i])) { solid = 1; break; }
        }
      }
      grid[i] = solid;
    }
  }
  return grid;
}

// Async loader for both PNGs. Resolves with { tilesheet, idle, run }.
function loadAssets() {
  const mk = (src) => new Promise((res, rej) => {
    const img = new Image();
    img.onload = () => res(img);
    img.onerror = rej;
    img.src = src;
  });
  return Promise.all([
    mk(CROSSING_TILESHEET_DATA),
    mk(HALLOKIN_IDLE_DATA),
    mk(HALLOKIN_RUN_DATA),
  ]).then(([tilesheet, idle, run]) => ({ tilesheet, idle, run }));
}

// Paint the entire tilemap onto an offscreen canvas. Returns the canvas.
function bakeTilemap(tilesheet) {
  const m = CROSSING_TILEMAP;
  const canvas = document.createElement('canvas');
  canvas.width = m.width * m.tileSize;
  canvas.height = m.height * m.tileSize;
  const ctx = canvas.getContext('2d');
  ctx.imageSmoothingEnabled = false;
  const layers = [m.layer1, m.layer2, m.layer3, m.layer4, m.layer5, m.layer6];
  for (const layer of layers) {
    for (let row = 0; row < m.height; row++) {
      for (let col = 0; col < m.width; col++) {
        const tile = layer[row * m.width + col];
        if (!tile) continue;
        const idx = tile - 1;
        const sx = (idx % m.sheetCols) * m.tileSize;
        const sy = ((idx / m.sheetCols) | 0) * m.tileSize;
        ctx.drawImage(tilesheet, sx, sy, m.tileSize, m.tileSize,
                      col * m.tileSize, row * m.tileSize, m.tileSize, m.tileSize);
      }
    }
  }
  return canvas;
}

window.HVData = {
  CROSSING_TILEMAP, CROSSING_TILESHEET_DATA,
  HALLOKIN_IDLE_DATA, HALLOKIN_RUN_DATA,
  TILE_PX, TILES_W, TILES_H, MAP_W, MAP_H, RENDER_SCALE,
  PLAYER_RADIUS, MOVE_SPEED,
  FRAME_W, FRAME_H, IDLE_FRAMES, IDLE_FPS, RUN_FRAMES, RUN_FPS,
  SPRITE_DRAW_W, SPRITE_DRAW_H,
  SPAWN_TILE,
  SOLID_IDS, DOCK_ID,
  buildSolidGrid, loadAssets, bakeTilemap,
};
